use crate::api::client::ApiClient;
use crate::constants::NO_PROJECT;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities::{format_duration_compact, normalize_time_entry_list_filters};
use std::collections::HashMap;

pub struct StatsCommand;

impl StatsCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = normalize_time_entry_list_filters(since, until)?;
        let entries = api_client.get_time_entries_filtered(since, until).await?;
        let lines = stats_lines(&entries);

        for line in lines {
            println!("{line}");
        }
        Ok(())
    }
}

fn stats_lines(entries: &[TimeEntry]) -> Vec<String> {
    let mut totals: HashMap<&str, i64> = HashMap::new();
    for entry in entries.iter().filter(|entry| entry.duration >= 0) {
        let project_name = entry
            .project
            .as_ref()
            .map(|project| project.name.as_str())
            .unwrap_or(NO_PROJECT);
        *totals.entry(project_name).or_default() += entry.duration;
    }

    let mut totals: Vec<(&str, i64)> = totals.into_iter().collect();
    totals.sort_by(|(name_a, duration_a), (name_b, duration_b)| {
        duration_b.cmp(duration_a).then_with(|| name_a.cmp(name_b))
    });

    let total_seconds: i64 = totals.iter().map(|(_, duration)| duration).sum();
    let mut lines: Vec<String> = totals
        .into_iter()
        .map(|(name, duration)| format!("{}  {name}", format_duration_compact(duration)))
        .collect();
    lines.push(format!("{}  Total", format_duration_compact(total_seconds)));
    lines
}

